/// <summary>
/// Método parm para el <c>container</c> de registros <c>recordCon</c>.
/// </summary>
/// <param name = "_recordCon"><c>container</c> de registros <c>recordCon</c></param>
/// <returns><c>container</c> de registros <c>recordCon</c></returns>
public container parmRecordCon(container _recordCon = recordCon)
{
    recordCon = _recordCon;

    return recordCon;
}

public static IFRUniversalInterfaceSystemShowInfoLog construct(Args _args)
{
    IFRUniversalInterfaceSystemShowInfoLog ifrUniversalInterfaceSystemShowInfoLog = new IFRUniversalInterfaceSystemShowInfoLog();

    if (_args && _args.record() && _args.record().tableId)
    {
        ifrUniversalInterfaceSystemShowInfoLog.parmRecordCon(ifrUniversalInterfaceSystemShowInfoLog.getRecordConFromArgs(_args));
    }

    return ifrUniversalInterfaceSystemShowInfoLog;
}

public static void main(Args _args)
{
    IFRUniversalInterfaceSystemShowInfoLog ifrUniversalInterfaceSystemShowInfoLog = IFRUniversalInterfaceSystemShowInfoLog::construct(_args);

    ifrUniversalInterfaceSystemShowInfoLog.run();
}

public container getRecordConFromArgs(Args _args)
{
    MultiSelectionHelper	            multiSelectionHelper;
    Set						            recordSet;
    IFRUniversalInterfaceSystemTable    ifrUniversalInterfaceSystemTable;

    if (_args && _args.caller() is FormRun)
    {
        recordSet				= new Set(Types::Record);
        multiselectionHelper	= MultiSelectionHelper::createFromCaller(_args.caller());

        ifrUniversalInterfaceSystemTable	= multiselectionHelper.getFirst();

        recordSet.add(ifrUniversalInterfaceSystemTable);

        return recordSet.pack();
    }
    else
    {
        return conNull();
    }
}

void run()
{
    IFRUniversalInterfaceSystemTable    ifrUniversalInterfaceSystemTable;
    SetEnumerator		                se;
    Common				                record;
    #OCCRetryCount

    try
    {
        ttsBegin;
        if (conLen(recordCon) > 0)
        {
            se = Set::create(recordCon).getEnumerator();
            while (se.moveNext())
            {
                record              = se.current();
                ifrUniversalInterfaceSystemTable  = record;

                if (ifrUniversalInterfaceSystemTable && conLen(ifrUniversalInterfaceSystemTable.ErrorLogContainer) > 0)
                {
                    infolog.clear();
                    infolog.import(ifrUniversalInterfaceSystemTable.ErrorLogContainer, true);
                }
            }
        }
        ttsCommit;
    }
    catch (Exception::Deadlock)
    {
        retry;
    }
    catch (Exception::UpdateConflict)
    {
        if (appl.ttsLevel() == 0)
        {
            if (xSession::currentRetryCount() >= #RetryNum)
            {
                throw Exception::UpdateConflictNotRecovered;
            }
            else
            {
                retry;
            }
        }
        else
        {
            throw Exception::UpdateConflict;
        }
    }
}
